public IEnumerable<SelectListItem> ProjectTypeOptions
{
    get
    {
        return Enum.GetValues(typeof(CLegalDashboardProject.eLegalDashboardProjectType))
            .Cast<CLegalDashboardProject.eLegalDashboardProjectType>()
            .Select(e => new SelectListItem
            {
                Value = ((int)e).ToString(),
                Text = CLegalDashboardProject.GetProjectTypeString(e)
            });
    }
}

